import { NavLink } from 'react-router-dom';
import { Calendar, Clock, Settings, LayoutGrid, Users, Menu, X, Video } from 'lucide-react';
import { useState } from 'react';
import './Sidebar.css';

const navItems = [
  { to: '/dashboard', icon: LayoutGrid, label: 'Event Types' },
  { to: '/meetings', icon: Users, label: 'Scheduled Events' },
  { to: '/availability', icon: Clock, label: 'Availability' },
];

export default function Sidebar() {
  const [mobileOpen, setMobileOpen] = useState(false);

  return (
    <>
      <button className="mobile-menu-btn" onClick={() => setMobileOpen(true)}>
        <Menu size={22} />
      </button>

      {mobileOpen && (
        <div className="sidebar-overlay" onClick={() => setMobileOpen(false)} />
      )}

      <aside className={`sidebar ${mobileOpen ? 'mobile-open' : ''}`}>
        <div className="sidebar-logo">
          <div className="logo-icon">
            <Calendar size={18} />
          </div>
          <span className="logo-text">Schedulr</span>
          <button className="sidebar-close" onClick={() => setMobileOpen(false)}>
            <X size={18} />
          </button>
        </div>

        <div className="sidebar-profile">
          <div className="avatar">JD</div>
          <div>
            <div className="profile-name">John Doe</div>
            <div className="profile-handle">schedulr.app/john</div>
          </div>
        </div>

        <nav className="sidebar-nav">
          {navItems.map(({ to, icon: Icon, label }) => (
            <NavLink
              key={to}
              to={to}
              className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
              onClick={() => setMobileOpen(false)}
            >
              <Icon size={18} />
              <span>{label}</span>
            </NavLink>
          ))}
        </nav>

        <div className="sidebar-bottom">
          <div className="sidebar-divider" />
          <a href="/book/30min" target="_blank" className="nav-item preview-link">
            <Video size={18} />
            <span>Preview Booking Page</span>
          </a>
        </div>
      </aside>
    </>
  );
}
